@Test public void testNormalisesMultipleHeads() {
    Document doc = Jsoup.parse("<html><head><title>First</title></head><head><meta charset='utf-8'></head><body><p>Content</p></body></html>");
    assertEquals("<html><head><title>First</title><meta charset=\"utf-8\"></head><body><p>Content</p></body></html>", TextUtil.stripNewlines(doc.html()));
}

@Test public void testNormalisesMultipleBodies() {
    Document doc = Jsoup.parse("<html><head></head><body><p>First</p></body><body><p>Second</p></body></html>");
    assertEquals("<html><head></head><body><p>First</p><p>Second</p></body></html>", TextUtil.stripNewlines(doc.html()));
}

@Test public void testNormalisesEmptyNoscriptInHead() {
    Document doc = Jsoup.parse("<html><head><noscript></noscript></head><body></body></html>");
    assertEquals("<html><head><noscript></noscript></head><body></body></html>", TextUtil.stripNewlines(doc.html()));
}
